class WordFilter:
    def __init__(self, words):
        self.lookup = {}
        for idx, w in enumerate(words):
            n = len(w)
            for i in range(n + 1):
                suffix = w[i:]
                for j in range(1, n + 1):
                    prefix = w[:j]
                    self.lookup[suffix + '#' + prefix] = idx
    def f(self, pref, suff):
        return self.lookup.get(suff + '#' + pref, -1)

