var WordFilter = function(words) {
    this.lookup = new Map();
    for (let idx = 0; idx < words.length; idx++) {
        const w = words[idx];
        const n = w.length;
        for (let i = 0; i <= n; i++) {
            const suffix = w.slice(i);
            for (let j = 1; j <= n; j++) {
                const prefix = w.slice(0, j);
                this.lookup.set(suffix + '#' + prefix, idx);
            }
        }
    }
};
WordFilter.prototype.f = function(pref, suff) {
    const key = suff + '#' + pref;
    return this.lookup.has(key) ? this.lookup.get(key) : -1;
};
